<template>
	<view v-if="showPopup" class="uni-popup" :class="[popupstyle, isDesktop ? 'fixforpc-z-index' : '']">
		<view @touchstart="touchstart">
			<uni-transition key="1" v-if="maskShow" name="mask" mode-class="fade" :styles="maskClass"
				:duration="duration" :show="showTrans" @click="onTap" />
			<uni-transition key="2" :mode-class="ani" name="content" :styles="transClass" :duration="duration"
				:show="showTrans" @click="onTap">
				<view class="uni-popup__wrapper" :style="getStyles" :class="[popupstyle]" @click="clear">
					<slot />
				</view>
			</uni-transition>
		</view>
		<!-- #ifdef H5 -->
		<keypress v-if="maskShow" @esc="onTap" />
		<!-- #endif -->
	</view>
</template>

<script>
	// #ifdef H5
	import keypress from './keypress.js'
	// #endif

	/**
	 * PopUp еј№еҮәеұӮ
	 * @description еј№еҮәеұӮз»„д»¶пјҢдёәдәҶи§ЈеҶійҒ®зҪ©еј№еұӮзҡ„й—®йўҳ
	 * @tutorial https://ext.dcloud.net.cn/plugin?id=329
	 * @property {String} type = [top|center|bottom|left|right|message|dialog|share] еј№еҮәж–№ејҸ
	 * 	@value top йЎ¶йғЁеј№еҮә
	 * 	@value center дёӯй—ҙеј№еҮә
	 * 	@value bottom еә•йғЁеј№еҮә
	 * 	@value left		е·Ұдҫ§еј№еҮә
	 * 	@value right  еҸідҫ§еј№еҮә
	 * 	@value message ж¶ҲжҒҜжҸҗзӨә
	 * 	@value dialog еҜ№иҜқжЎҶ
	 * 	@value share еә•йғЁеҲҶдә«зӨәдҫӢ
	 * @property {Boolean} animation = [true|false] жҳҜеҗҰејҖеҗҜеҠЁз”»
	 * @property {Boolean} maskClick = [true|false] и’ҷзүҲзӮ№еҮ»жҳҜеҗҰе…ій—ӯеј№зӘ—(еәҹејғ)
	 * @property {Boolean} isMaskClick = [true|false] и’ҷзүҲзӮ№еҮ»жҳҜеҗҰе…ій—ӯеј№зӘ—
	 * @property {String}  backgroundColor дё»зӘ—еҸЈиғҢжҷҜиүІ
	 * @property {String}  maskBackgroundColor и’ҷзүҲйўңиүІ
	 * @property {String}  borderRadius и®ҫзҪ®еңҶи§’(е·ҰдёҠгҖҒеҸідёҠгҖҒеҸідёӢе’Ңе·ҰдёӢ) зӨәдҫӢ:"10px 10px 10px 10px"
	 * @property {Boolean} safeArea		   жҳҜеҗҰйҖӮй…Қеә•йғЁе®үе…ЁеҢә
	 * @event {Function} change жү“ејҖе…ій—ӯеј№зӘ—и§ҰеҸ‘пјҢe={show: false}
	 * @event {Function} maskClick зӮ№еҮ»йҒ®зҪ©и§ҰеҸ‘
	 */

	export default {
		name: 'uniPopup',
		components: {
			// #ifdef H5
			keypress
			// #endif
		},
		emits: ['change', 'maskClick'],
		props: {
			// ејҖеҗҜеҠЁз”»
			animation: {
				type: Boolean,
				default: true
			},
			// еј№еҮәеұӮзұ»еһӢпјҢеҸҜйҖүеҖјпјҢtop: йЎ¶йғЁеј№еҮәеұӮпјӣbottomпјҡеә•йғЁеј№еҮәеұӮпјӣcenterпјҡе…ЁеұҸеј№еҮәеұӮ
			// message: ж¶ҲжҒҜжҸҗзӨә ; dialog : еҜ№иҜқжЎҶ
			type: {
				type: String,
				default: 'center'
			},
			// maskClick
			isMaskClick: {
				type: Boolean,
				default: null
			},
			// TODO 2 дёӘзүҲжң¬еҗҺеәҹејғеұһжҖ§ пјҢдҪҝз”Ё isMaskClick
			maskClick: {
				type: Boolean,
				default: null
			},
			backgroundColor: {
				type: String,
				default: 'none'
			},
			safeArea: {
				type: Boolean,
				default: true
			},
			maskBackgroundColor: {
				type: String,
				default: 'rgba(0, 0, 0, 0.4)'
			},
			borderRadius:{
				type: String,
			}
		},

		watch: {
			/**
			 * зӣ‘еҗ¬typeзұ»еһӢ
			 */
			type: {
				handler: function(type) {
					if (!this.config[type]) return
					this[this.config[type]](true)
				},
				immediate: true
			},
			isDesktop: {
				handler: function(newVal) {
					if (!this.config[newVal]) return
					this[this.config[this.type]](true)
				},
				immediate: true
			},
			/**
			 * зӣ‘еҗ¬йҒ®зҪ©жҳҜеҗҰеҸҜзӮ№еҮ»
			 * @param {Object} val
			 */
			maskClick: {
				handler: function(val) {
					this.mkclick = val
				},
				immediate: true
			},
			isMaskClick: {
				handler: function(val) {
					this.mkclick = val
				},
				immediate: true
			},
			// H5 дёӢзҰҒжӯўеә•йғЁж»ҡеҠЁ
			showPopup(show) {
				// #ifdef H5
				// fix by mehaotian еӨ„зҗҶ h5 ж»ҡеҠЁз©ҝйҖҸзҡ„й—®йўҳ
				document.getElementsByTagName('body')[0].style.overflow = show ? 'hidden' : 'visible'
				// #endif
			}
		},
		data() {
			return {
				duration: 300,
				ani: [],
				showPopup: false,
				showTrans: false,
				popupWidth: 0,
				popupHeight: 0,
				config: {
					top: 'top',
					bottom: 'bottom',
					center: 'center',
					left: 'left',
					right: 'right',
					message: 'top',
					dialog: 'center',
					share: 'bottom'
				},
				maskClass: {
					position: 'fixed',
					bottom: 0,
					top: 0,
					left: 0,
					right: 0,
					backgroundColor: 'rgba(0, 0, 0, 0.4)'
				},
				transClass: {
					backgroundColor: 'transparent',
					borderRadius: this.borderRadius || "0",
					position: 'fixed',
					left: 0,
					right: 0
				},
				maskShow: true,
				mkclick: true,
				popupstyle: 'top'
			}
		},
		computed: {
			getStyles() {
				let res = { backgroundColor: this.bg };
				if (this.borderRadius || "0") {
					res = Object.assign(res, { borderRadius: this.borderRadius })
				}
				return res;
			},
			isDesktop() {
				return this.popupWidth >= 500 && this.popupHeight >= 500
			},
			bg() {
				if (this.backgroundColor === '' || this.backgroundColor === 'none') {
					return 'transparent'
				}
				return this.backgroundColor
			}
		},
		mounted() {
			const fixSize = () => {
				const {
					windowWidth,
					windowHeight,
					windowTop,
					safeArea,
					screenHeight,
					safeAreaInsets
				} = uni.getSystemInfoSync()
				this.popupWidth = windowWidth
				this.popupHeight = windowHeight + (windowTop || 0)
				// TODO fix by mehaotian жҳҜеҗҰйҖӮй…Қеә•йғЁе®үе…ЁеҢә ,зӣ®еүҚеҫ®дҝЎios гҖҒе’Ң app ios и®Ўз®—жңүе·®ејӮпјҢйңҖиҰҒжЎҶжһ¶дҝ®еӨҚ
				if (safeArea && this.safeArea) {
					// #ifdef MP-WEIXIN
					this.safeAreaInsets = screenHeight - safeArea.bottom
					// #endif
					// #ifndef MP-WEIXIN
					this.safeAreaInsets = safeAreaInsets.bottom
					// #endif
				} else {
					this.safeAreaInsets = 0
				}
			}
			fixSize()
			// #ifdef H5
			// window.addEventListener('resize', fixSize)
			// this.$once('hook:beforeDestroy', () => {
			// 	window.removeEventListener('resize', fixSize)
			// })
			// #endif
		},
		// #ifndef VUE3
		// TODO vue2
		destroyed() {
			this.setH5Visible()
		},
		// #endif
		// #ifdef VUE3
		// TODO vue3
		unmounted() {
			this.setH5Visible()
		},
		// #endif
		activated() {
   	  this.setH5Visible(!this.showPopup);
    },
    deactivated() {
      this.setH5Visible(true);
    },
		created() {
			// this.mkclick =  this.isMaskClick || this.maskClick
			if (this.isMaskClick === null && this.maskClick === null) {
				this.mkclick = true
			} else {
				this.mkclick = this.isMaskClick !== null ? this.isMaskClick : this.maskClick
			}
			if (this.animation) {
				this.duration = 300
			} else {
				this.duration = 0
			}
			// TODO еӨ„зҗҶ message з»„д»¶з”ҹе‘Ҫе‘ЁжңҹејӮеёёзҡ„й—®йўҳ
			this.messageChild = null
			// TODO и§ЈеҶіеӨҙжқЎеҶ’жіЎзҡ„й—®йўҳ
			this.clearPropagation = false
			this.maskClass.backgroundColor = this.maskBackgroundColor
		},
		methods: {
			setH5Visible(visible = true) {
				// #ifdef H5
				// fix by mehaotian еӨ„зҗҶ h5 ж»ҡеҠЁз©ҝйҖҸзҡ„й—®йўҳ
				document.getElementsByTagName('body')[0].style.overflow =  visible ? "visible" : "hidden";
				// #endif
			},
			/**
			 * е…¬з”Ёж–№жі•пјҢдёҚжҳҫзӨәйҒ®зҪ©еұӮ
			 */
			closeMask() {
				this.maskShow = false
			},
			/**
			 * е…¬з”Ёж–№жі•пјҢйҒ®зҪ©еұӮзҰҒжӯўзӮ№еҮ»
			 */
			disableMask() {
				this.mkclick = false
			},
			// TODO nvue еҸ–ж¶ҲеҶ’жіЎ
			clear(e) {
				// #ifndef APP-NVUE
				e.stopPropagation()
				// #endif
				this.clearPropagation = true
			},

			open(direction) {
				// fix by mehaotian еӨ„зҗҶеҝ«йҖҹжү“ејҖе…ій—ӯзҡ„жғ…еҶө
				if (this.showPopup) {
					return
				}
				let innerType = ['top', 'center', 'bottom', 'left', 'right', 'message', 'dialog', 'share']
				if (!(direction && innerType.indexOf(direction) !== -1)) {
					direction = this.type
				}
				if (!this.config[direction]) {
					console.error('зјәе°‘зұ»еһӢпјҡ', direction)
					return
				}
				this[this.config[direction]]()
				this.$emit('change', {
					show: true,
					type: direction
				})
			},
			close(type) {
				this.showTrans = false
				this.$emit('change', {
					show: false,
					type: this.type
				})
				clearTimeout(this.timer)
				// // иҮӘе®ҡд№үе…ій—ӯдәӢд»¶
				// this.customOpen && this.customClose()
				this.timer = setTimeout(() => {
					this.showPopup = false
				}, 300)
			},
			// TODO еӨ„зҗҶеҶ’жіЎдәӢд»¶пјҢеӨҙжқЎзҡ„еҶ’жіЎдәӢд»¶жңүй—®йўҳ пјҢе…Ҳиҝҷж ·е…је®№
			touchstart() {
				this.clearPropagation = false
			},

			onTap() {
				if (this.clearPropagation) {
					// fix by mehaotian е…је®№ nvue
					this.clearPropagation = false
					return
				}
				this.$emit('maskClick')
				if (!this.mkclick) return
				this.close()
			},
			/**
			 * йЎ¶йғЁеј№еҮәж ·ејҸеӨ„зҗҶ
			 */
			top(type) {
				this.popupstyle = this.isDesktop ? 'fixforpc-top' : 'top'
				this.ani = ['slide-top']
				this.transClass = {
					position: 'fixed',
					left: 0,
					right: 0,
					backgroundColor: this.bg,
					borderRadius:this.borderRadius || "0"
				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
				this.$nextTick(() => {
					if (this.messageChild && this.type === 'message') {
						this.messageChild.timerClose()
					}
				})
			},
			/**
			 * еә•йғЁеј№еҮәж ·ејҸеӨ„зҗҶ
			 */
			bottom(type) {
				this.popupstyle = 'bottom'
				this.ani = ['slide-bottom']
				this.transClass = {
					position: 'fixed',
					left: 0,
					right: 0,
					bottom: 0,
					paddingBottom: this.safeAreaInsets + 'px',
					backgroundColor: this.bg,
					borderRadius:this.borderRadius || "0",
				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
			},
			/**
			 * дёӯй—ҙеј№еҮәж ·ејҸеӨ„зҗҶ
			 */
			center(type) {
				this.popupstyle = 'center'
				//еҫ®дҝЎе°ҸзЁӢеәҸдёӢпјҢз»„еҗҲеҠЁз”»дјҡеҮәзҺ°ж–Үеӯ—еҗ‘дёҠй—ӘеҠЁй—®йўҳпјҢеҶҚжӯӨеҒҡзү№ж®ҠеӨ„зҗҶ
				// #ifdef MP-WEIXIN
					this.ani = ['fade']
				// #endif
				// #ifndef MP-WEIXIN
					this.ani = ['zoom-out', 'fade']
				// #endif
				this.transClass = {
					position: 'fixed',
					/* #ifndef APP-NVUE */
					display: 'flex',
					flexDirection: 'column',
					/* #endif */
					bottom: 0,
					left: 0,
					right: 0,
					top: 0,
					justifyContent: 'center',
					alignItems: 'center',
					borderRadius:this.borderRadius || "0"
				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
			},
			left(type) {
				this.popupstyle = 'left'
				this.ani = ['slide-left']
				this.transClass = {
					position: 'fixed',
					left: 0,
					bottom: 0,
					top: 0,
					backgroundColor: this.bg,
					borderRadius:this.borderRadius || "0",
					/* #ifndef APP-NVUE */
					display: 'flex',
					flexDirection: 'column'
					/* #endif */
				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
			},
			right(type) {
				this.popupstyle = 'right'
				this.ani = ['slide-right']
				this.transClass = {
					position: 'fixed',
					bottom: 0,
					right: 0,
					top: 0,
					backgroundColor: this.bg,
					borderRadius:this.borderRadius || "0",
					/* #ifndef APP-NVUE */
					display: 'flex',
					flexDirection: 'column'
					/* #endif */
				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
			}
		}
	}
</script>
<style lang="scss">
	.uni-popup {
		position: fixed;
		/* #ifndef APP-NVUE */
		z-index: 99;

		/* #endif */
		&.top,
		&.left,
		&.right {
			/* #ifdef H5 */
			top: var(--window-top);
			/* #endif */
			/* #ifndef H5 */
			top: 0;
			/* #endif */
		}

		.uni-popup__wrapper {
			/* #ifndef APP-NVUE */
			display: block;
			/* #endif */
			position: relative;

			/* iphonex зӯүе®үе…ЁеҢәи®ҫзҪ®пјҢеә•йғЁе®үе…ЁеҢәйҖӮй…Қ */
			/* #ifndef APP-NVUE */
			// padding-bottom: constant(safe-area-inset-bottom);
			// padding-bottom: env(safe-area-inset-bottom);
			/* #endif */
			&.left,
			&.right {
				/* #ifdef H5 */
				padding-top: var(--window-top);
				/* #endif */
				/* #ifndef H5 */
				padding-top: 0;
				/* #endif */
				flex: 1;
			}
		}
	}

	.fixforpc-z-index {
		/* #ifndef APP-NVUE */
		z-index: 999;
		/* #endif */
	}

	.fixforpc-top {
		top: 0;
	}
</style>
